body.script:
(function () {
  const BAR_ID = "resilio-news-bar";
  const ATTR_ORIG_TOP = "data-resilio-orig-top";
  const ATTR_DONE = "data-resilio-newsbar-done";

  const BAR_H_FALLBACK = 50;

  function toNumPx(v) {
    const n = parseFloat(v);
    return Number.isFinite(n) ? n : 0;
  }

  function setCSSVar(name, valuePx) {
    document.documentElement.style.setProperty(name, valuePx);
  }

  // Find the "main header": the top-most fixed/sticky full-width element near the top.
  function findMainHeader(barEl, barH) {
    const candidates = [];
    const all = document.querySelectorAll("body *");

    for (const el of all) {
      if (el === barEl) continue;

      const cs = getComputedStyle(el);
      if (cs.display === "none" || cs.visibility === "hidden" || cs.opacity === "0") continue;

      const pos = cs.position;
      if (pos !== "fixed" && pos !== "sticky") continue;

      const r = el.getBoundingClientRect();
      if (r.height < 40) continue;
      if (r.width < window.innerWidth * 0.6) continue;

      // Must be at/near the top area (bar occupies top 50px)
      if (r.top > barH + 2) continue;

      // Avoid picking tiny fixed UI widgets
      if (r.height > window.innerHeight * 0.6) continue;

      const z = parseInt(cs.zIndex || "0", 10) || 0;
      candidates.push({ el, z, h: r.height, top: r.top });
    }

    // Prefer highest z-index, then tallest (headers tend to be tall)
    candidates.sort((a,b) => (b.z - a.z) || (b.h - a.h));
    return candidates.length ? candidates[0].el : null;
  }

  function apply() {
    const bar = document.getElementById(BAR_ID);
    if (!bar) return;

    document.body.classList.add("resilio-newsbar-on");

    const barH = Math.round(bar.getBoundingClientRect().height) || BAR_H_FALLBACK;
    setCSSVar("--resilio-newsbar-h", barH + "px");

    // 1) Find and move the main header down so it sits under the bar.
    const header = findMainHeader(bar, barH);

    let headerH = 0;
    if (header) {
      const r = header.getBoundingClientRect();
      headerH = Math.round(r.height) || 0;

      // Only set top if it is pinned to the top (top:auto sticky can still be fine, but we want it below bar)
      header.style.setProperty("top", barH + "px", "important");
      header.setAttribute("data-resilio-main-header", "1");
    }
    setCSSVar("--resilio-header-h", headerH + "px");

    // 2) Nudge ALL sticky elements by +barH (preserving their original top).
    //    Key: this prevents sticky subnavs from sitting 50px too high after header moves.
    const all = document.querySelectorAll("body *");
    for (const el of all) {
      if (el === bar) continue;
      if (header && (el === header || header.contains(el))) continue; // don't mess with header internals

      const cs = getComputedStyle(el);
      if (cs.position !== "sticky") continue;

      // Sticky only works when top is set. If it's auto, don't touch it.
      if (!cs.top || cs.top === "auto") continue;

      // Avoid double-applying
      if (el.getAttribute(ATTR_DONE) === "1") continue;

      // Store original computed top (could be "0px", "80px", etc.)
      el.setAttribute(ATTR_ORIG_TOP, cs.top);
      el.setAttribute(ATTR_DONE, "1");

      // Add bar height on top of existing sticky offset
      el.style.setProperty("top", `calc(${cs.top} + ${barH}px)`, "important");
    }
  }

  function reset() {
    // Restore sticky tops we changed
    const changed = document.querySelectorAll(`[${ATTR_DONE}="1"]`);
    changed.forEach(el => {
      const orig = el.getAttribute(ATTR_ORIG_TOP);
      if (orig) el.style.setProperty("top", orig, "important");
      el.removeAttribute(ATTR_ORIG_TOP);
      el.removeAttribute(ATTR_DONE);
    });

    // Restore header top if we set it
    const header = document.querySelector('[data-resilio-main-header="1"]');
    if (header) {
      header.style.removeProperty("top");
      header.removeAttribute("data-resilio-main-header");
    }
  }

  function reapply() {
    reset();
    apply();
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", apply);
  } else {
    apply();
  }

  // Re-apply on resize (header height / sticky behavior can change)
  window.addEventListener("resize", () => {
    clearTimeout(window.__resilioNewsbarResizeTO);
    window.__resilioNewsbarResizeTO = setTimeout(reapply, 50);
  });

  // SPA / dynamic pages: catch newly inserted sticky subnavs
  const mo = new MutationObserver(() => {
    clearTimeout(window.__resilioNewsbarMOTO);
    window.__resilioNewsbarMOTO = setTimeout(() => {
      // Only apply without resetting everything (preserves stability)
      apply();
    }, 50);
  });
  mo.observe(document.documentElement, { childList: true, subtree: true });

})();

div.script:
// when the DOM is ready
            document.addEventListener("DOMContentLoaded", function() { 
              // get the the span element
              const yrSpan = document.querySelector('.auto-year-update');
              // get the current year
              const currentYr = new Date().getFullYear();
              // set the year span element's text to the current year
              yrSpan.textContent = currentYr;
            });
